import type { QualtricsInsightsStore } from './types';

import { getReq } from '@meli/server-context';

import { getConfigProps } from './utils';

export function createQualtricsInsightsStore(): QualtricsInsightsStore {
  const req = getReq();

  return {
    enabled: false,
    props: {},
    configProps: getConfigProps('qualtricsInsights'),
    debugMode: !!(
      req.header('x-qualtrics-insights-debug') ||
      req.query.qualtrics_insights_debug
    ),
  };
}
